"""
Integration tests for Prism.js pattern generation.

Tests the complete generation pipeline for all 6 languages.
"""

import subprocess
import pytest
from pathlib import Path


@pytest.fixture
def project_root():
    """Get project root directory."""
    return Path(__file__).parent.parent.parent.parent


@pytest.fixture
def generated_dir(project_root):
    """Get generated files directory."""
    return project_root / 'zlsp' / 'generated'


@pytest.fixture
def bifrost_syntax_dir(project_root):
    """Get bifrost syntax directory."""
    return project_root / 'zOS' / 'bifrost' / 'src' / 'syntax'


@pytest.fixture
def static_js_dir(project_root):
    """Get zCloud static JS directory (where /static/ is served from)."""
    return project_root / 'zCloud' / 'static' / 'js'


class TestGenerationPipeline:
    """Test the complete generation pipeline."""
    
    def test_generator_runs_successfully(self, project_root):
        """Test that generator script runs without errors."""
        result = subprocess.run(
            ['python3', '-m', 'zlsp.generators.generate_prism_zolo'],
            cwd=project_root,
            capture_output=True,
            text=True
        )
        
        assert result.returncode == 0, f"Generator failed:\n{result.stderr}"
        assert 'Generation complete!' in result.stdout
    
    def test_all_languages_generated(self, generated_dir):
        """Test that all 6 language files are generated."""
        expected_files = [
            'prism-zolo.js',
            'prism-zspark.js',
            'prism-zui.js',
            'prism-zschema.js',
            'prism-zconfig.js',
            'prism-zenv.js',
        ]
        
        for filename in expected_files:
            path = generated_dir / filename
            assert path.exists(), f"{filename} not generated in {generated_dir}"
            assert path.stat().st_size > 0, f"{filename} is empty"
    
    def test_all_languages_copied_to_bifrost_syntax(self, bifrost_syntax_dir):
        """Test that all 6 language files are copied to bifrost syntax directory."""
        expected_files = [
            'prism-zolo.js',
            'prism-zspark.js',
            'prism-zui.js',
            'prism-zschema.js',
            'prism-zconfig.js',
            'prism-zenv.js',
        ]
        
        for filename in expected_files:
            path = bifrost_syntax_dir / filename
            assert path.exists(), f"{filename} not copied to {bifrost_syntax_dir}"
            assert path.stat().st_size > 0, f"{filename} in bifrost syntax is empty"
    
    def test_all_languages_copied_to_static_js(self, static_js_dir):
        """Test that all 6 language files are copied to zCloud static JS directory."""
        expected_files = [
            'prism-zolo.js',
            'prism-zspark.js',
            'prism-zui.js',
            'prism-zschema.js',
            'prism-zconfig.js',
            'prism-zenv.js',
        ]
        
        for filename in expected_files:
            path = static_js_dir / filename
            assert path.exists(), f"{filename} not copied to {static_js_dir}"
            assert path.stat().st_size > 0, f"{filename} in zCloud static is empty"


class TestGeneratedFileContent:
    """Test the content of generated files."""
    
    @pytest.fixture(params=[
        'zolo', 'zspark', 'zui', 'zschema', 'zconfig', 'zenv'
    ])
    def language_name(self, request):
        return request.param
    
    @pytest.fixture
    def language_file(self, generated_dir, language_name):
        return generated_dir / f'prism-{language_name}.js'
    
    def test_file_has_prism_definition(self, language_file, language_name):
        """Test that file defines Prism.languages correctly."""
        content = language_file.read_text()
        assert f'Prism.languages.{language_name}' in content
    
    def test_file_has_header_comment(self, language_file):
        """Test that file has generation header."""
        content = language_file.read_text()
        assert '/**' in content
        assert 'Generated by zlsp/zlsp/generators/generate_prism_zolo.py' in content
        assert 'DO NOT EDIT MANUALLY' in content
    
    def test_file_has_comment_pattern(self, language_file):
        """Test that all files have comment pattern (in base or inherited)."""
        content = language_file.read_text()
        
        # Check if this is base zolo or extended language
        is_base = 'Prism.languages.zolo = {' in content
        is_extended = "Prism.languages.extend('zolo'," in content
        
        if is_base:
            # Base zolo should have comment pattern explicitly
            assert "'comment':" in content or '"comment":' in content
            assert '#' in content  # Comment pattern includes #
        elif is_extended:
            # Extended languages inherit comment from base zolo
            assert "Prism.languages.extend('zolo'," in content
        else:
            pytest.fail("File doesn't match base or extended pattern structure")
    
    def test_file_has_punctuation_pattern(self, language_file):
        """Test that all files have punctuation pattern (in base or inherited)."""
        content = language_file.read_text()
        
        # Check if this is base zolo or extended language
        is_base = 'Prism.languages.zolo = {' in content
        is_extended = "Prism.languages.extend('zolo'," in content
        
        if is_base:
            # Base zolo should have punctuation pattern explicitly
            assert "'punctuation':" in content or '"punctuation":' in content
        elif is_extended:
            # Extended languages inherit punctuation from base zolo
            assert "Prism.languages.extend('zolo'," in content
        else:
            pytest.fail("File doesn't match base or extended pattern structure")
    
    def test_file_ends_with_closing_brace(self, language_file):
        """Test that file ends properly (either `};` for base or `});` for extended)."""
        content = language_file.read_text()
        
        # Check if this is base zolo or extended language
        is_base = 'Prism.languages.zolo = {' in content
        is_extended = "Prism.languages.extend('zolo'," in content
        
        if is_base:
            assert content.strip().endswith('};'), "Base language should end with '};'"
        elif is_extended:
            assert content.strip().endswith('});'), "Extended language should end with '});'"
        else:
            pytest.fail("File doesn't match base or extended pattern structure")
    
    def test_file_has_no_syntax_errors(self, language_file):
        """Test basic JavaScript syntax validity."""
        content = language_file.read_text()
        
        # Check file ends with proper closing (either `};` for base or `});` for extended)
        is_base = 'Prism.languages.zolo = {' in content
        is_extended = "Prism.languages.extend('zolo'," in content
        
        if is_base:
            assert content.strip().endswith('};'), "Base language should end with '}'"
        elif is_extended:
            assert content.strip().endswith('});'), "Extended language should end with '})'"
        
        # Check braces are balanced
        open_braces = content.count('{')
        close_braces = content.count('}')
        assert open_braces == close_braces, "Unbalanced braces"
        
        # Check brackets are balanced
        open_brackets = content.count('[')
        close_brackets = content.count(']')
        assert open_brackets == close_brackets, "Unbalanced brackets"
        
        # Note: We don't check parentheses balance because regex patterns
        # include non-capturing groups (?:, lookaheads (?=, etc. that make
        # simple counting inaccurate


