class TestFileSynchronization:
    """Test that generated files are properly synchronized."""
    
    @pytest.fixture(params=[
        'zolo', 'zspark', 'zui', 'zschema', 'zconfig', 'zenv'
    ])
    def language_name(self, request):
        return request.param
    
    def test_generated_and_deployed_files_match(
        self, generated_dir, bifrost_syntax_dir, static_js_dir, language_name
    ):
        """Test that generated and deployed files have identical content."""
        generated_file = generated_dir / f'prism-{language_name}.js'
        bifrost_syntax_file = bifrost_syntax_dir / f'prism-{language_name}.js'
        static_js_file = static_js_dir / f'prism-{language_name}.js'
        
        generated_content = generated_file.read_text()
        bifrost_syntax_content = bifrost_syntax_file.read_text()
        static_js_content = static_js_file.read_text()
        
        assert generated_content == bifrost_syntax_content, \
            f"prism-{language_name}.js differs between generated/ and bifrost/syntax/"
        assert generated_content == static_js_content, \
            f"prism-{language_name}.js differs between generated/ and zCloud/static/js/"


class TestPatternOrdering:
    """Test that patterns are in correct order."""
    
    @pytest.fixture(params=[
        'zolo', 'zspark', 'zui', 'zschema', 'zconfig', 'zenv'
    ])
    def language_file(self, generated_dir, request):
        language_name = request.param
        return generated_dir / f'prism-{language_name}.js'
    
    def test_comment_comes_first(self, language_file):
        """Test that comment pattern comes first (in base or inherited)."""
        content = language_file.read_text()

        # Check if this is base zolo or extended language
        is_base = 'Prism.languages.zolo = {' in content
        is_extended = "Prism.languages.extend('zolo'," in content

        if is_base:
            # Base zolo should have comment explicitly first
            comment_pos = content.find("'comment':")
            if comment_pos == -1:
                comment_pos = content.find('"comment":')
            
            lang_def_pos = content.find('Prism.languages.')
            assert comment_pos > lang_def_pos, "Comment should be first pattern in base"
        elif is_extended:
            # Extended languages inherit comment from base zolo
            # Just verify it extends properly
            assert "Prism.languages.extend('zolo'," in content
        else:
            pytest.fail("File doesn't match base or extended pattern structure")
    
    def test_punctuation_comes_last(self, language_file):
        """Test that punctuation pattern comes last (in base or inherited)."""
        content = language_file.read_text()

        # Check if this is base zolo or extended language
        is_base = 'Prism.languages.zolo = {' in content
        is_extended = "Prism.languages.extend('zolo'," in content

        if is_base:
            # Base zolo should have punctuation explicitly last
            punct_pos = content.find("'punctuation':")
            if punct_pos == -1:
                punct_pos = content.find('"punctuation":')
            
            closing_pos = content.rfind('};')
            
            # Punctuation should be near the end (before closing brace)
            assert punct_pos < closing_pos, "Punctuation should be last pattern in base"
            assert closing_pos - punct_pos < 200, "Punctuation should be close to end"
        elif is_extended:
            # Extended languages inherit punctuation from base zolo
            # Just verify it extends properly
            assert "Prism.languages.extend('zolo'," in content
        else:
            pytest.fail("File doesn't match base or extended pattern structure")


class TestRegression:
    """Regression tests for specific bugs."""
    
    def test_settings_page_bug_fixed(self, generated_dir):
        """
        Regression test: Settings_Page should be colored as root-key.
        
        This was the original bug that started the generator project.
        """
        content = (generated_dir / 'prism-zolo.js').read_text()
        
        # Check that root-key pattern exists
        assert "'root-key':" in content or '"root-key":' in content
        
        # Check that it matches any case (lowercase or Capital)
        assert '[a-zA-Z]' in content
        
        # Check that it has column 0 detection (capturing or non-capturing group)
        assert ('(^|' in content or '(?:^|' in content or '(?<=\\n)' in content), \
            "Root key pattern must match at column 0"
